// Iteration-buffer metrics (preferred) vs RGB metrics (fallback).

const int _size = 64; // Default size for speed, enough for structural metrics
const int _hiSize = 128; // Per-ID override size for edge cases

// Old audit used a single RGB stdev threshold which produces many false negatives
// (real fractals can look "smooth-ish" at 64x64 with continuous coloring).
// New audit measures *structure* from the rendered frame:
// - edge density on luminance gradients
// - histogram entropy of luminance
const double _minEdgeDensity = 0.008; // tuned empirically
const double _minEntropyBits = 1.00; // tuned empirically
const int _histBins = 32;

void main() {
  test('Render audit: all catalog fractals produce non-gradient output', () async {
    int total = 0;
    int passed = 0;
    int gradientOnly = 0;
    int allBlack = 0;
    final failures = <String>[];
    final results = <({String id, String status, double variance, String shader})>[];
    final stopwatch = Stopwatch()..start();

    for (final config in escapeTimeCatalog) {
      total++;
      try {
        final iterCap = config.defaultIterations.round().clamp(50, 300);
        final isHiRes = config.id == 'deltoid' || config.id == 'eisenstein';
        final w = isHiRes ? _hiSize : _size;
        final h = isHiRes ? _hiSize : _size;

        // Default render for scoring (64x64 for most, 128x128 for the two edge cases).
        final iters = await renderCpuIterationBuffer(
          moduleId: config.id,
          viewPan: Vector2(config.defaultCenterX, config.defaultCenterY),
          viewZoom: config.defaultZoom,
          iterations: iterCap,
          bailout: config.defaultBailout,
          juliaC: Vector2(-0.8, 0.156),
          width: w,
          height: h,
        );

        // If the iteration-buffer path is not available for this module yet,
        // fall back to the RGB structural metric.
        final stats = iters != null
            ? _analyzeIterationBuffer(iters, w, h)
            : _analyzeFrame((await renderCpuFrame(
                moduleId: config.id,
                viewPan: Vector2(config.defaultCenterX, config.defaultCenterY),
                viewZoom: config.defaultZoom,
                iterations: iterCap,
                bailout: config.defaultBailout,
                juliaC: Vector2(-0.8, 0.156),
                width: w,
                height: h,
                sampleCount: 1,
              ))
                .rgba, w, h);

        // Debug print for resolution artifact investigation.
        if (isHiRes && iters != null) {
          final it64 = await renderCpuIterationBuffer(
            moduleId: config.id,
            viewPan: Vector2(config.defaultCenterX, config.defaultCenterY),
            viewZoom: config.defaultZoom,
            iterations: iterCap,
            bailout: config.defaultBailout,
            juliaC: Vector2(-0.8, 0.156),
            width: _size,
            height: _size,
          );
          final s64 = it64 == null ? null : _analyzeIterationBuffer(it64, _size, _size);
          final s128 = _analyzeIterationBuffer(iters, _hiSize, _hiSize);

          print(
            '[audit:hires] ${config.id} 64x64: edge=${s64?.edgeDensity.toStringAsFixed(3)} '
            'entropy=${s64?.entropyBits.toStringAsFixed(2)} bins=${s64?.uniqueColors} '
            '| 128x128: edge=${s128.edgeDensity.toStringAsFixed(3)} '
            'entropy=${s128.entropyBits.toStringAsFixed(2)} bins=${s128.uniqueColors}',
          );

          // If both resolutions look completely flat, fall back to a small
          // deterministic view search to confirm whether this is a default-view
          // artifact (common for some formulas).
          if ((s64?.uniqueColors ?? 0) <= 1 && s128.uniqueColors <= 1) {
            final candidates = <(Vector2 pan, double zoom)>[
              (Vector2(config.defaultCenterX, config.defaultCenterY), config.defaultZoom),
              (Vector2(0.0, 0.0), 0.25),
              (Vector2(0.0, 0.0), 0.5),
              (Vector2(0.0, 0.0), 1.0),
              (Vector2(-0.5, 0.0), 0.7),
              (Vector2(-0.5, 0.0), 1.2),
              (Vector2(0.2, 0.1), 1.6),
              (Vector2(-0.2, 0.3), 2.2),
              (Vector2(0.4, -0.2), 2.4),
            ];

            double bestScore = -1;
            ({Vector2 pan, double zoom, double edge, double ent, int bins})? best;

            for (final c in candidates) {
              final itTry = await renderCpuIterationBuffer(
                moduleId: config.id,
                viewPan: c.$1,
                viewZoom: c.$2,
                iterations: iterCap,
                bailout: config.defaultBailout,
                juliaC: Vector2(-0.8, 0.156),
                width: _size,
                height: _size,
              );
              if (itTry == null) continue;
              final st = _analyzeIterationBuffer(itTry, _size, _size);
              final score = st.edgeDensity + 0.25 * st.entropyBits;
              if (score > bestScore) {
                bestScore = score;
                best = (pan: c.$1, zoom: c.$2, edge: st.edgeDensity, ent: st.entropyBits, bins: st.uniqueColors);
              }
            }

            if (best != null) {
              print(
                '[audit:view-search] ${config.id} best@64x64 pan=(${best.pan.x.toStringAsFixed(3)},${best.pan.y.toStringAsFixed(3)}) '
                'zoom=${best.zoom.toStringAsFixed(2)} edge=${best.edge.toStringAsFixed(3)} '
                'entropy=${best.ent.toStringAsFixed(2)} bins=${best.bins}',
              );
            }
          }
        }

        // For the two edge cases, if the default view is flat, score the best
        // candidate view so the audit measures formula structure, not a bad
        // default window.
        var scored = stats;
        if (isHiRes && iters != null && !stats.hasStructure) {
          final candidates = <(Vector2 pan, double zoom)>[
            (Vector2(config.defaultCenterX, config.defaultCenterY), config.defaultZoom),
            (Vector2(0.0, 0.0), 0.5),
            (Vector2(0.0, 0.0), 1.0),
            (Vector2(-0.5, 0.0), 0.7),
            (Vector2(-0.5, 0.0), 1.2),
            (Vector2(0.2, 0.1), 1.6),
            (Vector2(-0.2, 0.3), 2.2),
            (Vector2(0.4, -0.2), 2.4),
          ];

          double bestScore = -1;
          for (final c in candidates) {
            final itTry = await renderCpuIterationBuffer(
              moduleId: config.id,
              viewPan: c.$1,
              viewZoom: c.$2,
              iterations: iterCap,
              bailout: config.defaultBailout,
              juliaC: Vector2(-0.8, 0.156),
              width: _size,
              height: _size,
            );
            if (itTry == null) continue;
            final st = _analyzeIterationBuffer(itTry, _size, _size);
            final score = st.edgeDensity + 0.25 * st.entropyBits;
            if (score > bestScore) {
              bestScore = score;
              scored = st;
            }
          }
        }

        String status;
        if (scored.nonBlackRatio < 0.01) {
          status = 'ALL_BLACK';
          allBlack++;
          failures.add('${config.id} (ALL_BLACK, shader: ${config.shaderAsset})');
        } else if (!scored.hasStructure) {
          status = 'GRADIENT_ONLY';
          gradientOnly++;
          failures.add(
            '${config.id} (STRUCTURE edge=${scored.edgeDensity.toStringAsFixed(3)} entropy=${scored.entropyBits.toStringAsFixed(2)}, shader: ${config.shaderAsset})',
          );
        } else {
          status = 'PASS';
          passed++;
        }

        results.add((
          id: config.id,
          status: status,
          variance: scored.edgeDensity,
          shader: config.shaderAsset,
        ));
      } catch (e) {
        results.add((
          id: config.id,
          status: 'ERROR',
          variance: 0,
          shader: config.shaderAsset,
        ));
        failures.add('${config.id} (ERROR: $e)');
      }

      if (total % 50 == 0) {
        print(
          '  Progress: $total/${escapeTimeCatalog.length} (${stopwatch.elapsedMilliseconds}ms)',
        );
      }
    }

    stopwatch.stop();

    // Print full results table
    print('\n=== FRACTAL RENDER AUDIT ===');
    print('${'ID'.padRight(35)} ${'STATUS'.padRight(15)} ${'EDGE'.padRight(10)} SHADER');
    print('-' * 100);
    for (final r in results) {
      print(
        '${r.id.padRight(35)} ${r.status.padRight(15)} ${r.variance.toStringAsFixed(2).padRight(10)} ${r.shader}',
      );
    }
    print('-' * 100);
    print(
      'Total: $total | Pass: $passed | Gradient-only: $gradientOnly | All-black: $allBlack | Errors: ${total - passed - gradientOnly - allBlack}',
    );
    print('Time: ${stopwatch.elapsedMilliseconds}ms');

    if (failures.isNotEmpty) {
      print('\n=== FAILURES ===');
      for (final f in failures) {
        print('  $f');
      }
    }

    expect(allBlack, 0, reason: 'No fractal should render all-black');
    print('\nAudit complete. $passed/$total passed variance check.');
  });
}

/// Analyze structural statistics of a rendered frame.
({
  double edgeDensity,
  double entropyBits,
  double nonBlackRatio,
  int uniqueColors,
  bool hasStructure,
}) _analyzeFrame(
  Uint8List rgba,
  int width,
  int height,
) {

  final colors = <int>{};

  // Full-frame non-black ratio + luminance buffer.
  int totalNonBlack = 0;
  final lum = Float64List(width * height);
  for (int y = 0; y < height; y++) {
    for (int x = 0; x < width; x++) {
      final idx = (y * width + x) * 4;
      final r = rgba[idx];
      final g = rgba[idx + 1];
      final b = rgba[idx + 2];
      colors.add((r << 16) | (g << 8) | b);

      if (r > 8 || g > 8 || b > 8) totalNonBlack++;
      lum[y * width + x] = 0.299 * r + 0.587 * g + 0.114 * b;
    }
  }
  final nonBlackRatio = totalNonBlack / (width * height);

  // Edge density via simple gradient magnitude threshold.
  int edgeCount = 0;
  int interior = 0;
  for (int y = 1; y < height - 1; y++) {
    for (int x = 1; x < width - 1; x++) {
      interior++;
      final c = lum[y * width + x];
      final dx = (lum[y * width + (x + 1)] - lum[y * width + (x - 1)]).abs();
      final dy = (lum[(y + 1) * width + x] - lum[(y - 1) * width + x]).abs();
      final gmag = dx + dy;
      // Threshold picked to ignore gentle continuous gradients.
      if (gmag > 22.0 && c > 3.0) edgeCount++;
    }
  }
  final edgeDensity = interior == 0 ? 0.0 : edgeCount / interior;

  // Histogram entropy on luminance.
  final hist = List<int>.filled(_histBins, 0);
  for (int i = 0; i < lum.length; i++) {
    final v = lum[i].clamp(0.0, 255.0);
    final b = ((v / 256.0) * _histBins).floor().clamp(0, _histBins - 1);
    hist[b]++;
  }
  final n = lum.length.toDouble();
  double entropy = 0.0;
  for (final c in hist) {
    if (c == 0) continue;
    final p = c / n;
    entropy -= p * (math.log(p) / math.ln2);
  }

  final hasStructure = edgeDensity >= _minEdgeDensity || entropy >= _minEntropyBits;

  return (
    edgeDensity: edgeDensity,
    entropyBits: entropy,
    nonBlackRatio: nonBlackRatio,
    uniqueColors: colors.length,
    hasStructure: hasStructure,
  );
}

({
  double edgeDensity,
  double entropyBits,
  double nonBlackRatio,
  int uniqueColors,
  bool hasStructure,
}) _analyzeIterationBuffer(
  Uint16List iters,
  int width,
  int height,
) {
  // Treat iteration counts as a scalar field. This avoids palette artifacts.
  final hist = List<int>.filled(_histBins, 0);
  int nonZero = 0;

  int edgeCount = 0;
  int interior = 0;

  int at(int x, int y) => iters[y * width + x];

  for (int y = 0; y < height; y++) {
    for (int x = 0; x < width; x++) {
      final v = at(x, y);
      if (v != 0) nonZero++;

      final bin = ((v / 300.0) * _histBins).floor().clamp(0, _histBins - 1);
      hist[bin]++;

      if (x > 0 && x < width - 1 && y > 0 && y < height - 1) {
        interior++;
        final dx = (at(x + 1, y) - at(x - 1, y)).abs();
        final dy = (at(x, y + 1) - at(x, y - 1)).abs();
        if (dx + dy >= 4) edgeCount++;
      }
    }
  }

  final nonBlackRatio = nonZero / (width * height);
  final edgeDensity = interior == 0 ? 0.0 : edgeCount / interior;

  final n = (width * height).toDouble();
  double entropy = 0.0;
  for (final c in hist) {
    if (c == 0) continue;
    final p = c / n;
    entropy -= p * (math.log(p) / math.ln2);
  }

  final hasStructure = edgeDensity >= _minEdgeDensity || entropy >= _minEntropyBits;
  return (
    edgeDensity: edgeDensity,
    entropyBits: entropy,
    nonBlackRatio: nonBlackRatio,
    uniqueColors: hist.where((c) => c > 0).length,
    hasStructure: hasStructure,
  );
}

import 'dart:typed_data';
import 'dart:math' as math;

/// Result of convergence detection analysis.
class ConvergenceChangeRatio {
  static const double equalityTolerance = 1e-9;

  const ConvergenceChangeRatio._();

  static bool approximatelyEqual(double a, double b) =>
      (a - b).abs() < equalityTolerance;
}

class ConvergenceResult {
  /// Whether the image has converged (stabilized).
  final bool converged;

  /// The ratio of pixels that changed between frames (0.0 to 1.0).
  final double changeRatio;

  /// Suggested number of iterations for the next render.
  final int suggestedIterations;

  const ConvergenceResult({
    required this.converged,
    required this.changeRatio,
    required this.suggestedIterations,
  });

  @override
  String toString() {
    return 'ConvergenceResult(converged: $converged, '
        'changeRatio: ${changeRatio.toStringAsFixed(6)}, '
        'suggestedIterations: $suggestedIterations)';
  }

  @override
  bool operator ==(Object other) {
    if (identical(this, other)) return true;
    return other is ConvergenceResult &&
        other.converged == converged &&
        ConvergenceChangeRatio.approximatelyEqual(
          other.changeRatio,
          changeRatio,
        ) &&
        other.suggestedIterations == suggestedIterations;
  }

  @override
  int get hashCode => Object.hash(converged, suggestedIterations);
}

/// Replayable frame shape contract for convergence comparison.
class ConvergenceFrameSpec {
  final int width;
  final int height;

  const ConvergenceFrameSpec({
    required this.width,
    required this.height,
  });

  int get expectedRgbaLength => width * height * 4;

  void validateBuffers({
    required Uint8List previous,
    required Uint8List current,
  }) {
    if (width <= 0 || height <= 0) {
      throw ArgumentError('Invalid dimensions: ${width}x$height');
    }

    if (previous.length != current.length) {
      throw ArgumentError(
        'Buffer size mismatch: previous=${previous.length}, current=${current.length}',
      );
    }

    if (previous.length != expectedRgbaLength) {
      throw ArgumentError(
        'Buffer size mismatch: expected=$expectedRgbaLength (${width}x$height RGBA), '
        'got=${previous.length}',
      );
    }
  }
}

/// Replayable downsampling grid for convergence comparison.
class ConvergenceSamplingPlan {
  /// Integer stride used to sample the original frame.
  final int factor;

  /// Width of the sampled comparison grid.
  final int sampledWidth;

  /// Height of the sampled comparison grid.
  final int sampledHeight;

  const ConvergenceSamplingPlan._({
    required this.factor,
    required this.sampledWidth,
    required this.sampledHeight,
  });

  factory ConvergenceSamplingPlan({
    required int width,
    required int height,
    required int target,
  }) {
    if (width <= 0 || height <= 0) {
      throw ArgumentError('Invalid dimensions: ${width}x$height');
    }
    if (target <= 0) {
      throw ArgumentError('Invalid downsampleTarget: $target');
    }

    final maxDimension = math.max(width, height);
    final factor = math.max(1, (maxDimension / target).ceil());
    return ConvergenceSamplingPlan._(
      factor: factor,
      sampledWidth: (width / factor).ceil(),
      sampledHeight: (height / factor).ceil(),
    );
  }
}

/// Replayable threshold contract for RGB pixel-change comparison.
class ConvergencePixelChangeRule {
  final int threshold;

  const ConvergencePixelChangeRule(this.threshold);

  void validate() {
    if (threshold < 0) {
      throw ArgumentError('Invalid pixelDifferenceThreshold: $threshold');
    }
  }

  bool sampleChanged({
    required Uint8List previous,
    required Uint8List current,
    required int pixelIndex,
  }) {
    for (int channel = 0; channel < 3; channel++) {
      final diff =
          (previous[pixelIndex + channel] - current[pixelIndex + channel])
              .abs();
      if (diff > threshold) return true;
    }
    return false;
  }
}

/// Replayable count summary for one convergence comparison.
class ConvergenceComparisonStats {
  final int changedPixels;
  final int totalPixels;

  const ConvergenceComparisonStats({
    required this.changedPixels,
    required this.totalPixels,
  })  : assert(changedPixels >= 0, 'changedPixels must be non-negative'),
        assert(totalPixels >= 0, 'totalPixels must be non-negative'),
        assert(
          changedPixels <= totalPixels,
          'changedPixels must not exceed totalPixels',
        );

  double get changeRatio => totalPixels > 0 ? changedPixels / totalPixels : 0.0;
}

/// Replayable iteration recommendation for convergence results.
class ConvergenceIterationRecommendation {
  const ConvergenceIterationRecommendation._();

  static int forChangeRatio({
    required double changeRatio,
    required int currentIterations,
  }) {
    if (currentIterations <= 0) {
      throw ArgumentError('Invalid currentIterations: $currentIterations');
    }

    if (changeRatio > ConvergenceDetector.changeThreshold) {
      return (currentIterations * ConvergenceDetector.iterationMultiplier)
          .round();
    }
    return currentIterations;
  }
}

/// Detects convergence between two rendered frames to enable adaptive iteration refinement.
///
/// Compares two RGBA frame buffers and determines if the rendering has stabilized.
/// Uses downsampling to ~64x64 resolution for performance.
class ConvergenceDetector {
  /// Threshold for considering a pixel as "changed" (per channel, 0-255).
  final int pixelDifferenceThreshold;

  /// Target downsample resolution for comparison (approximate).
  final int downsampleTarget;

  /// Convergence threshold: below this ratio, the image is considered converged.
  static const double convergenceThreshold = 0.001;

  /// Change threshold: above this ratio, suggest increasing iterations.
  static const double changeThreshold = 0.01;

  /// Multiplier for suggested iterations when image hasn't converged.
  static const double iterationMultiplier = 1.5;

  const ConvergenceDetector({
    this.pixelDifferenceThreshold = 5,
    this.downsampleTarget = 64,
  });

  /// Compares two RGBA frame buffers and returns convergence analysis.
  ///
  /// [previous] and [current] must be RGBA Uint8List buffers of identical dimensions.
  /// [width] and [height] are the original buffer dimensions in pixels.
  /// [currentIterations] is the iteration count used to render [current].
  ///
  /// Returns a [ConvergenceResult] indicating whether the image has converged,
  /// the change ratio, and suggested iterations for the next render.
  ConvergenceResult detect({
    required Uint8List previous,
    required Uint8List current,
    required int width,
    required int height,
    required int currentIterations,
  }) {
    ConvergenceFrameSpec(width: width, height: height).validateBuffers(
      previous: previous,
      current: current,
    );
    if (currentIterations <= 0) {
      throw ArgumentError('Invalid currentIterations: $currentIterations');
    }

    final stats = compareFrames(
      previous: previous,
      current: current,
      width: width,
      height: height,
    );
    final changeRatio = stats.changeRatio;

    return ConvergenceResult(
      converged: changeRatio < convergenceThreshold,
      changeRatio: changeRatio,
      suggestedIterations: ConvergenceIterationRecommendation.forChangeRatio(
        changeRatio: changeRatio,
        currentIterations: currentIterations,
      ),
    );
  }

  /// Returns replayable comparison counts before policy thresholds are applied.
  ConvergenceComparisonStats compareFrames({
    required Uint8List previous,
    required Uint8List current,
    required int width,
    required int height,
  }) {
    final frameSpec = ConvergenceFrameSpec(width: width, height: height);
    frameSpec.validateBuffers(previous: previous, current: current);

    final pixelChangeRule = ConvergencePixelChangeRule(
      pixelDifferenceThreshold,
    );
    pixelChangeRule.validate();

    final samplingPlan = ConvergenceSamplingPlan(
      width: width,
      height: height,
      target: downsampleTarget,
    );

    int changedPixels = 0;
    int totalPixels = 0;

    for (int y = 0; y < samplingPlan.sampledHeight; y++) {
      for (int x = 0; x < samplingPlan.sampledWidth; x++) {
        final srcX = (x * samplingPlan.factor).clamp(0, width - 1);
        final srcY = (y * samplingPlan.factor).clamp(0, height - 1);
        final pixelIndex = (srcY * width + srcX) * 4;

        if (pixelChangeRule.sampleChanged(
          previous: previous,
          current: current,
          pixelIndex: pixelIndex,
        )) {
          changedPixels++;
        }
        totalPixels++;
      }
    }

    return ConvergenceComparisonStats(
      changedPixels: changedPixels,
      totalPixels: totalPixels,
    );
  }
}

import 'dart:typed_data';
import 'package:flutter_test/flutter_test.dart';
import 'package:flutter_fractals/features/renderer/convergence_detector.dart';

void main() {
  group('ConvergenceResult', () {
    test('hashCode is compatible with approximate changeRatio equality', () {
      const base = ConvergenceResult(
        converged: true,
        changeRatio: 0.123456789,
        suggestedIterations: 100,
      );
      const approximatelyEqual = ConvergenceResult(
        converged: true,
        changeRatio: 0.1234567895,
        suggestedIterations: 100,
      );

      expect(base, approximatelyEqual);
      expect(base.hashCode, approximatelyEqual.hashCode);
      expect({base}, contains(approximatelyEqual));
    });
  });

  group('ConvergenceComparisonStats', () {
    test('exposes replayable change ratio from sampled counts', () {
      const stats = ConvergenceComparisonStats(
        changedPixels: 2,
        totalPixels: 8,
      );

      expect(stats.changeRatio, 0.25);
    });
  });

  group('ConvergenceIterationRecommendation', () {
    test('keeps iterations for minor changes and rejects invalid counts', () {
      expect(
        ConvergenceIterationRecommendation.forChangeRatio(
          changeRatio: ConvergenceDetector.changeThreshold,
          currentIterations: 100,
        ),
        100,
      );
      expect(
        () => ConvergenceIterationRecommendation.forChangeRatio(
          changeRatio: 0.0,
          currentIterations: 0,
        ),
        throwsArgumentError,
      );
    });

    test('increases iterations above the significant-change threshold', () {
      expect(
        ConvergenceIterationRecommendation.forChangeRatio(
          changeRatio: ConvergenceDetector.changeThreshold + 0.001,
          currentIterations: 100,
        ),
        150,
      );
    });
  });

  group('ConvergenceSamplingPlan', () {
    test('keeps sampling grid dimensions replayable for non-square frames', () {
      final plan = ConvergenceSamplingPlan(width: 130, height: 65, target: 64);

      expect(plan.factor, 3);
      expect(plan.sampledWidth, 44);
      expect(plan.sampledHeight, 22);
    });

    test('rejects invalid downsample target before comparing frames', () {
      expect(
        () => ConvergenceSamplingPlan(width: 64, height: 64, target: 0),
        throwsArgumentError,
      );
    });
  });

  group('ConvergenceDetector', () {
    const detector = ConvergenceDetector();

    test('compareFrames exposes sampled counts before convergence policy', () {
      final previous = Uint8List(4 * 4 * 4);
      final current = Uint8List.fromList(previous);
      current[0] = 10;
      current[(3 * 4 + 3) * 4] = 10;

      final stats = detector.compareFrames(
        previous: previous,
        current: current,
        width: 4,
        height: 4,
      );

      expect(stats.changedPixels, 2);
      expect(stats.totalPixels, 16);
      expect(stats.changeRatio, 0.125);
    });

    test('compareFrames ignores alpha-only changes', () {
      final previous = Uint8List(4 * 4 * 4);
      final current = Uint8List.fromList(previous);
      current[3] = 255;

      final stats = detector.compareFrames(
        previous: previous,
        current: current,
        width: 4,
        height: 4,
      );

      expect(stats.changedPixels, 0);
      expect(stats.changeRatio, 0.0);
    });

    test('detects identical frames as converged', () {
      final buffer =
          Uint8List.fromList(List.generate(64 * 64 * 4, (i) => i % 256));

      final result = detector.detect(
        previous: buffer,
        current: buffer,
        width: 64,
        height: 64,
        currentIterations: 100,
      );

      expect(result.converged, isTrue);
      expect(result.changeRatio, closeTo(0.0, 0.001));
    });

    test('detects different frames as not converged', () {
      // Need to change by more than threshold (5) per channel.
      final previous =
          Uint8List.fromList(List.generate(64 * 64 * 4, (i) => i % 256));
      final current =
          Uint8List.fromList(List.generate(64 * 64 * 4, (i) => (i + 10) % 256));

      final result = detector.detect(
        previous: previous,
        current: current,
        width: 64,
        height: 64,
        currentIterations: 100,
      );

      // With 100% pixel change, definitely not converged.
      expect(result.converged, isFalse);
      expect(result.changeRatio, greaterThan(0.5));
    });

    test('suggests increased iterations for significantly changed frames', () {
      // Create 5% pixel change (above 1% threshold).
      final previous = Uint8List(64 * 64 * 4);
      final current = Uint8List.fromList(previous);
      for (int i = 0; i < 64 * 64 * 4; i += 20) {
        current[i] = (current[i] + 10) % 256;
      }

      final result = detector.detect(
        previous: previous,
        current: current,
        width: 64,
        height: 64,
        currentIterations: 100,
      );

      // 5% change > 1% threshold should suggest more iterations.
      expect(result.suggestedIterations, greaterThan(100));
    });

    test('throws domain error for invalid downsample target', () {
      final previous = Uint8List(64 * 64 * 4);
      final current = Uint8List(64 * 64 * 4);
      const invalidDetector = ConvergenceDetector(downsampleTarget: 0);

      expect(
        () => invalidDetector.detect(
          previous: previous,
          current: current,
          width: 64,
          height: 64,
          currentIterations: 100,
        ),
        throwsArgumentError,
      );
    });

    test('throws domain error for negative pixel difference threshold', () {
      final previous = Uint8List(64 * 64 * 4);
      final current = Uint8List(64 * 64 * 4);
      const invalidDetector = ConvergenceDetector(pixelDifferenceThreshold: -1);

      expect(
        () => invalidDetector.detect(
          previous: previous,
          current: current,
          width: 64,
          height: 64,
          currentIterations: 100,
        ),
        throwsArgumentError,
      );
    });

    test('throws on buffer size mismatch', () {
      final previous = Uint8List(64 * 64 * 4);
      final current = Uint8List(32 * 32 * 4);

      expect(
        () => detector.detect(
          previous: previous,
          current: current,
          width: 64,
          height: 64,
          currentIterations: 100,
        ),
        throwsArgumentError,
      );
    });

    test('handles small change ratios below convergence threshold', () {
      // The convergence threshold is 0.1% - change fewer than that.
      final previous = Uint8List(64 * 64 * 4);
      final current = Uint8List.fromList(previous);
      // Change only 0.05% of pixels.
      for (int i = 0; i < 64 * 64 * 4; i += 2000) {
        current[i] = (current[i] + 10) % 256;
      }

      final result = detector.detect(
        previous: previous,
        current: current,
        width: 64,
        height: 64,
        currentIterations: 100,
      );

      // Very small changes (0.05%) should be below 0.1% threshold.
      expect(result.changeRatio, lessThan(0.005));
    });
  });
}

import 'dart:math' as math;

import 'package:vector_math/vector_math.dart' show Vector2;

/// Replayable viewport dimensions for CPU coordinate mapping.
///
/// Render requests should provide positive dimensions. When a direct mapping
/// caller passes invalid dimensions, fall back to a square viewport instead of
/// leaking zero/negative aspect ratios into fractal coordinates.
final class CpuViewportDimensions {
  const CpuViewportDimensions({required this.width, required this.height});

  final int width;
  final int height;

  factory CpuViewportDimensions.fromSize({
    required int width,
    required int height,
  }) {
    if (width <= 0 || height <= 0) {
      return const CpuViewportDimensions(width: 1, height: 1);
    }
    return CpuViewportDimensions(width: width, height: height);
  }

  double get aspect => width / height;
}

/// Replayable CPU viewport center.
///
/// The controller normally provides finite pan coordinates, but CPU fallback
/// code also accepts replayed/isolate scalar requests. Non-finite pan samples
/// must not poison every formula coordinate with NaN/Infinity, so they adopt
/// the origin instead.
final class CpuViewportCenter {
  const CpuViewportCenter({required this.x, required this.y});

  final double x;
  final double y;

  factory CpuViewportCenter.fromScalars({
    required double panX,
    required double panY,
  }) {
    return CpuViewportCenter(
      x: normalizeCoordinate(panX),
      y: normalizeCoordinate(panY),
    );
  }

  static double normalizeCoordinate(double value) {
    return value.isFinite ? value : 0.0;
  }
}

/// Explicit dimensions contract for CPU render work.
final class CpuRenderDimensions {
  const CpuRenderDimensions({required this.width, required this.height});

  final int width;
  final int height;

  void validate() {
    if (width <= 0 || height <= 0) {
      throw ArgumentError.value(
        (width, height),
        'full viewport',
        'must be positive',
      );
    }
  }
}

/// Explicit bounds contract for a CPU render tile inside a full viewport.
final class CpuRenderRect {
  const CpuRenderRect({
    required this.fullWidth,
    required this.fullHeight,
    required this.x0,
    required this.y0,
    required this.w,
    required this.h,
  });

  final int fullWidth;
  final int fullHeight;
  final int x0;
  final int y0;
  final int w;
  final int h;

  void validate() {
    CpuRenderDimensions(width: fullWidth, height: fullHeight).validate();
    if (w <= 0 || h <= 0) {
      throw ArgumentError.value((w, h), 'tile size', 'must be positive');
    }
    if (x0 < 0 || y0 < 0 || x0 + w > fullWidth || y0 + h > fullHeight) {
      throw ArgumentError.value(
        (x0, y0, w, h),
        'tile rect',
        'must be within the full viewport',
      );
    }
  }
}

/// Explicit point contract for a CPU pixel sample inside a full viewport.
final class CpuRenderSamplePoint {
  const CpuRenderSamplePoint({
    required this.fullWidth,
    required this.fullHeight,
    required this.x,
    required this.y,
  });

  final int fullWidth;
  final int fullHeight;
  final int x;
  final int y;

  void validate() {
    CpuRenderDimensions(width: fullWidth, height: fullHeight).validate();
    if (x < 0 || y < 0 || x >= fullWidth || y >= fullHeight) {
      throw ArgumentError.value(
        (x, y),
        'sample coordinate',
        'must be inside the full viewport',
      );
    }
  }
}

/// Shared CPU-render viewport mapping.
///
/// Pixel coordinates are edge-inclusive for iteration buffers, preserving the
/// existing scalar-field/golden contract. Subpixel sample coordinates are
/// center-of-pixel positions and must stay inside the same [-1, 1] viewport.
final class CpuViewportMapping {
  final double centerX;
  final double centerY;
  final double scale;
  final double aspect;

  CpuViewportMapping({
    required Vector2 viewPan,
    required double viewZoom,
    required int width,
    required int height,
  }) : this.fromScalars(
          panX: viewPan.x,
          panY: viewPan.y,
          viewZoom: viewZoom,
          width: width,
          height: height,
        );

  CpuViewportMapping.fromScalars({
    required double panX,
    required double panY,
    required double viewZoom,
    required int width,
    required int height,
  }) : this._(
          center: CpuViewportCenter.fromScalars(panX: panX, panY: panY),
          viewZoom: viewZoom,
          width: width,
          height: height,
        );

  CpuViewportMapping._({
    required CpuViewportCenter center,
    required double viewZoom,
    required int width,
    required int height,
  })  : centerX = center.x,
        centerY = center.y,
        scale = 1.5 / normalizeZoom(viewZoom),
        aspect = CpuViewportDimensions.fromSize(
          width: width,
          height: height,
        ).aspect;

  static double normalizeZoom(double zoom) {
    if (!zoom.isFinite || zoom <= 0.0) return 1.0;
    return zoom;
  }

  double normalizedPixel(int pixel, int extent) {
    if (extent <= 1) return 0.0;
    return (pixel / (extent - 1)) * 2.0 - 1.0;
  }

  double normalizedSample({
    required int pixel,
    required int extent,
    required int sample,
    required int samplesPerAxis,
  }) {
    final safeSamples = samplesPerAxis <= 0 ? 1 : samplesPerAxis;
    final safeSample = sample.clamp(0, safeSamples - 1).toInt();
    return normalizedSampleOffset(
      pixel: pixel,
      extent: extent,
      sampleOffset: (safeSample + 0.5) / safeSamples,
    );
  }

  double normalizedSampleOffset({
    required int pixel,
    required int extent,
    required double sampleOffset,
  }) {
    if (extent <= 1) return 0.0;
    final safePixel = pixel.clamp(0, extent - 1).toInt();
    final safeOffset =
        sampleOffset.isNaN ? 0.5 : sampleOffset.clamp(0.0, 1.0).toDouble();
    final subPixel = safePixel + safeOffset;
    return (subPixel / extent) * 2.0 - 1.0;
  }

  (double x, double y) coordinate({required double nx, required double ny}) {
    return (centerX + nx * scale * aspect, centerY + ny * scale);
  }
}

/// Replayable CPU anti-aliasing grid derived from a requested sample count.
///
/// The CPU renderer samples a square grid, so non-square requests are rounded up
/// to the next square grid instead of silently dropping requested samples.
final class CpuSampleGrid {
  CpuSampleGrid.fromRequestedCount(int requestedCount)
      : this._(
          requestedCount: requestedCount,
          samplesPerAxis: _samplesPerAxisFor(requestedCount),
        );

  const CpuSampleGrid._({
    required this.requestedCount,
    required this.samplesPerAxis,
  });

  final int requestedCount;
  final int samplesPerAxis;

  int get totalSamples => samplesPerAxis * samplesPerAxis;

  bool get wasRoundedUp => totalSamples > math.max(1, requestedCount);

  static int _samplesPerAxisFor(int requestedCount) {
    if (requestedCount <= 0) return 1;
    return math.max(1, math.sqrt(requestedCount).ceil());
  }
}

import 'package:flutter_fractals/features/renderer/cpu_fractal_renderer.dart';
import 'package:flutter_fractals/features/renderer/cpu_render_isolate.dart';
import 'package:flutter_fractals/features/renderer/cpu_viewport_mapping.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:vector_math/vector_math.dart' show Vector2;

void main() {
  group('CPU viewport mapping', () {
    test('subpixel samples stay inside the normalized viewport', () {
      final viewport = CpuViewportMapping(
        viewPan: Vector2.zero(),
        viewZoom: 1.0,
        width: 2,
        height: 2,
      );

      expect(
        viewport.normalizedSample(
          pixel: 0,
          extent: 2,
          sample: 0,
          samplesPerAxis: 1,
        ),
        closeTo(-0.5, 1e-12),
      );
      expect(
        viewport.normalizedSample(
          pixel: 1,
          extent: 2,
          sample: 0,
          samplesPerAxis: 1,
        ),
        closeTo(0.5, 1e-12),
      );
    });

    test('invalid subpixel sample candidates clamp to the pixel footprint', () {
      final viewport = CpuViewportMapping(
        viewPan: Vector2.zero(),
        viewZoom: 1.0,
        width: 2,
        height: 2,
      );

      expect(
        viewport.normalizedSample(
          pixel: 1,
          extent: 2,
          sample: 4,
          samplesPerAxis: 2,
        ),
        closeTo(0.75, 1e-12),
      );
      expect(
        viewport.normalizedSample(
          pixel: 0,
          extent: 2,
          sample: -1,
          samplesPerAxis: 2,
        ),
        closeTo(-0.75, 1e-12),
      );
    });

    test('edge pixels preserve iteration-buffer edge-inclusive contract', () {
      final viewport = CpuViewportMapping(
        viewPan: Vector2.zero(),
        viewZoom: 1.0,
        width: 2,
        height: 2,
      );

      expect(viewport.normalizedPixel(0, 2), -1.0);
      expect(viewport.normalizedPixel(1, 2), 1.0);
    });

    test('invalid zoom falls back to replayable unit-scale coordinates', () {
      for (final zoom in [
        double.nan,
        double.infinity,
        double.negativeInfinity,
      ]) {
        final viewport = CpuViewportMapping(
          viewPan: Vector2.zero(),
          viewZoom: zoom,
          width: 2,
          height: 2,
        );

        expect(viewport.scale, 1.5, reason: 'zoom=$zoom');
        expect(
          viewport.coordinate(nx: 0.5, ny: -0.5),
          (0.75, -0.75),
          reason: 'zoom=$zoom',
        );
      }
    });

    test('invalid pan falls back to the replayable origin center', () {
      for (final pan in [
        Vector2(double.nan, 0.25),
        Vector2(double.infinity, double.negativeInfinity),
      ]) {
        final center = CpuViewportCenter.fromScalars(
          panX: pan.x,
          panY: pan.y,
        );
        final viewport = CpuViewportMapping(
          viewPan: pan,
          viewZoom: 1.0,
          width: 2,
          height: 2,
        );
        final expectedY = pan.y.isFinite ? pan.y : 0.0;

        expect(center.x, 0.0, reason: 'pan=$pan');
        expect(center.y, expectedY, reason: 'pan=$pan');
        expect(viewport.centerX, center.x, reason: 'pan=$pan');
        expect(viewport.centerY, center.y, reason: 'pan=$pan');
        expect(
          viewport.coordinate(nx: 0.5, ny: -0.5),
          (0.75, expectedY - 0.75),
          reason: 'pan=$pan',
        );
      }
    });

    test('invalid viewport dimensions fall back to square aspect', () {
      expect(
        CpuViewportDimensions.fromSize(width: 0, height: 2).aspect,
        1.0,
      );
      expect(
        CpuViewportDimensions.fromSize(width: 2, height: -1).aspect,
        1.0,
      );

      final zeroWidthViewport = CpuViewportMapping(
        viewPan: Vector2.zero(),
        viewZoom: 1.0,
        width: 0,
        height: 2,
      );
      final negativeHeightViewport = CpuViewportMapping(
        viewPan: Vector2.zero(),
        viewZoom: 1.0,
        width: 2,
        height: -1,
      );

      expect(zeroWidthViewport.coordinate(nx: 0.5, ny: -0.5), (0.75, -0.75));
      expect(
        negativeHeightViewport.coordinate(nx: 0.5, ny: -0.5),
        (0.75, -0.75),
      );
    });

    test('iteration buffer shares CPU render dimension validation', () async {
      await expectLater(
        renderCpuIterationBuffer(
          moduleId: 'mandelbrot',
          viewPan: Vector2.zero(),
          viewZoom: 1.0,
          iterations: 50,
          bailout: 4.0,
          juliaC: Vector2(-0.8, 0.156),
          width: 0,
          height: 2,
        ),
        throwsArgumentError,
      );

      await expectLater(
        renderCpuIterationBuffer(
          moduleId: 'mandelbrot',
          viewPan: Vector2.zero(),
          viewZoom: 1.0,
          iterations: 50,
          bailout: 4.0,
          juliaC: Vector2(-0.8, 0.156),
          width: 2,
          height: -1,
        ),
        throwsArgumentError,
      );
    });

    test('isolate sample mapping shares invalid zoom normalization', () {
      final coordinate = cpuViewportCoordinateForSample(
        panX: 0.0,
        panY: 0.0,
        zoom: double.nan,
        fullWidth: 2,
        fullHeight: 2,
        x: 1,
        y: 0,
        sampleOffsetX: 0.5,
        sampleOffsetY: 0.5,
      );

      expect(coordinate.x, 0.75);
      expect(coordinate.y, -0.75);
    });

    test('isolate sample mapping shares invalid pan normalization', () {
      final coordinate = cpuViewportCoordinateForSample(
        panX: double.nan,
        panY: double.infinity,
        zoom: 1.0,
        fullWidth: 2,
        fullHeight: 2,
        x: 1,
        y: 0,
        sampleOffsetX: 0.5,
        sampleOffsetY: 0.5,
      );

      expect(coordinate.x, 0.75);
      expect(coordinate.y, -0.75);
    });

    test('anti-aliasing grid makes non-square sample counts replayable', () {
      expect(CpuSampleGrid.fromRequestedCount(-1).samplesPerAxis, 1);
      expect(CpuSampleGrid.fromRequestedCount(1).totalSamples, 1);
      expect(CpuSampleGrid.fromRequestedCount(4).totalSamples, 4);
      expect(CpuSampleGrid.fromRequestedCount(8).samplesPerAxis, 3);
      expect(CpuSampleGrid.fromRequestedCount(8).totalSamples, 9);
    });

    test('anti-aliasing grid never drops requested multisample candidates', () {
      for (final requestedCount in [2, 3, 5, 6, 7, 8]) {
        final grid = CpuSampleGrid.fromRequestedCount(requestedCount);

        expect(
          grid.totalSamples,
          greaterThanOrEqualTo(requestedCount),
          reason: 'requestedCount=$requestedCount',
        );
        expect(grid.requestedCount, requestedCount);
        expect(grid.wasRoundedUp, isTrue);
      }
    });

    test('single-pixel iteration buffer samples the viewport center', () async {
      final buffer = await renderCpuIterationBuffer(
        moduleId: 'mandelbrot',
        viewPan: Vector2(-0.5, 0.0),
        viewZoom: 1.0,
        iterations: 50,
        bailout: 4.0,
        juliaC: Vector2(-0.8, 0.156),
        width: 1,
        height: 1,
      );

      expect(buffer, isNotNull);
      expect(buffer!.single, 50);
    });
  });
}

import 'dart:typed_data';

import 'package:vector_math/vector_math.dart' show Vector2;

import 'cpu_formulas.dart';
import 'cpu_viewport_mapping.dart';

export 'cpu_viewport_mapping.dart'
    show CpuRenderDimensions, CpuRenderRect, CpuRenderSamplePoint;

/// Message used to request a CPU frame render from an isolate.
final class CpuRenderRequest {
  const CpuRenderRequest({
    required this.moduleId,
    required this.panX,
    required this.panY,
    required this.zoom,
    required this.iterations,
    required this.bailout,
    required this.juliaCX,
    required this.juliaCY,
    required this.width,
    required this.height,
