    rgba: bytes,
  );
}

/// Renders one CPU RGBA tile from an explicit full-viewport rectangle.
///
/// This pure raster helper is shared by direct, full-frame isolate, and tile
/// isolate render paths so they fail on the same invalid dimensions and sample
/// the same viewport coordinates.
Uint8List renderCpuRectRgba({
  required String moduleId,
  required double panX,
  required double panY,
  required double zoom,
  required int iterations,
  required double bailout,
  required double juliaCX,
  required double juliaCY,
  required int fullWidth,
  required int fullHeight,
  required int x0,
  required int y0,
  required int w,
  required int h,
  required int sampleCount,
}) {
  CpuRenderRect(
    fullWidth: fullWidth,
    fullHeight: fullHeight,
    x0: x0,
    y0: y0,
    w: w,
    h: h,
  ).validate();

  final bytes = Uint8List(w * h * 4);
  final sampleGrid = CpuSampleGrid.fromRequestedCount(sampleCount);

  final juliaC = Vector2(juliaCX, juliaCY);
  final formula = cpuFormulaForModuleId(moduleId);
  final viewport = CpuViewportMapping.fromScalars(
    panX: panX,
    panY: panY,
    viewZoom: zoom,
    width: fullWidth,
    height: fullHeight,
  );

  for (int ty = 0; ty < h; ty++) {
    final y = y0 + ty;
    for (int tx = 0; tx < w; tx++) {
      final x = x0 + tx;

      double rAcc = 0;
      double gAcc = 0;
      double bAcc = 0;

      for (int sy = 0; sy < sampleGrid.samplesPerAxis; sy++) {
        for (int sx = 0; sx < sampleGrid.samplesPerAxis; sx++) {
          final nx = viewport.normalizedSample(
            pixel: x,
            extent: fullWidth,
            sample: sx,
            samplesPerAxis: sampleGrid.samplesPerAxis,
          );
          final ny = viewport.normalizedSample(
            pixel: y,
            extent: fullHeight,
            sample: sy,
            samplesPerAxis: sampleGrid.samplesPerAxis,
          );
          final coordinate = viewport.coordinate(nx: nx, ny: ny);

          final color = formula(
            coordinate.$1,
            coordinate.$2,
            iterations,
            bailout,
            juliaC,
          );
          rAcc += color.$1;
          gAcc += color.$2;
          bAcc += color.$3;
        }
      }

      final idx = (ty * w + tx) * 4;
      bytes[idx + 0] = (rAcc / sampleGrid.totalSamples).clamp(0, 255).round();
      bytes[idx + 1] = (gAcc / sampleGrid.totalSamples).clamp(0, 255).round();
      bytes[idx + 2] = (bAcc / sampleGrid.totalSamples).clamp(0, 255).round();
      bytes[idx + 3] = 255;
    }
  }

  return bytes;
}

import 'package:flutter_test/flutter_test.dart';
import 'package:vector_math/vector_math.dart' show Vector2;

import 'package:flutter_fractals/features/renderer/cpu_formulas.dart';
import 'package:flutter_fractals/features/renderer/cpu_render_isolate.dart';

void main() {
  group('CPU render viewport mapping', () {
    test('keeps opposite edge pixel centers symmetric around pan', () {
      final left = cpuViewportCoordinateForSample(
        panX: -0.5,
        panY: 0.25,
        zoom: 3.0,
        fullWidth: 4,
        fullHeight: 2,
        x: 0,
        y: 0,
        sampleOffsetX: 0.5,
        sampleOffsetY: 0.5,
      );
      final right = cpuViewportCoordinateForSample(
        panX: -0.5,
        panY: 0.25,
        zoom: 3.0,
        fullWidth: 4,
        fullHeight: 2,
        x: 3,
        y: 1,
        sampleOffsetX: 0.5,
        sampleOffsetY: 0.5,
      );

      expect(left.x + right.x, closeTo(-1.0, 1e-12));
      expect(left.y + right.y, closeTo(0.5, 1e-12));
    });

    test('rejects sample coordinates outside the full viewport before clamping',
        () {
      expect(
        () => cpuViewportCoordinateForSample(
          panX: -0.5,
          panY: 0.25,
          zoom: 3.0,
          fullWidth: 4,
          fullHeight: 2,
          x: 4,
          y: 0,
          sampleOffsetX: 0.5,
          sampleOffsetY: 0.5,
        ),
        throwsA(
          isA<ArgumentError>().having(
            (error) => error.name,
            'name',
            'sample coordinate',
          ),
        ),
      );
    });

    test('rejects tile rectangles outside the full viewport before sampling', () {
      const request = CpuTileRenderRequest(
        moduleId: 'mandelbrot',
        panX: 0.0,
        panY: 0.0,
        zoom: 1.0,
        iterations: 32,
        bailout: 4.0,
        juliaCX: -0.8,
        juliaCY: 0.156,
        fullWidth: 4,
        fullHeight: 4,
        x0: 3,
        y0: 0,
        w: 2,
        h: 1,
        sampleCount: 1,
      );

      expect(
        () => renderCpuTileInIsolate(request),
        throwsA(
          isA<ArgumentError>().having(
            (error) => error.message,
            'message',
            contains('within the full viewport'),
          ),
        ),
      );
    });

    test('maps a one-pixel frame to the requested pan center', () {
      const request = CpuRenderRequest(
        moduleId: 'mandelbrot',
        panX: -0.5,
        panY: 0.25,
        zoom: 3.0,
        iterations: 32,
        bailout: 4.0,
        juliaCX: -0.8,
        juliaCY: 0.156,
        width: 1,
        height: 1,
        sampleCount: 1,
      );

      final frame = renderCpuFrameInIsolate(request);
      final expected = cpuFormulaForModuleId(request.moduleId)(
        request.panX,
        request.panY,
        request.iterations,
        request.bailout,
        Vector2(request.juliaCX, request.juliaCY),
      );

      expect(frame.rgba, hasLength(4));
      expect(frame.rgba[0], expected.$1.clamp(0, 255).round());
      expect(frame.rgba[1], expected.$2.clamp(0, 255).round());
      expect(frame.rgba[2], expected.$3.clamp(0, 255).round());
      expect(frame.rgba[3], 255);
    });
  });
}

import 'dart:math' as math;

/// Replayable CPU iteration budget policy for zoom-dependent refinement.
///
/// CPU rendering has preview/refine/slow-mode entry points that must agree on
/// how a zoom sample is sanitized before adding deep-zoom iteration headroom.
/// Keeping this pure avoids timer-driven render paths depending on Dart's
/// `log(...).round()` behavior for malformed zoom values.
final class CpuIterationBudget {
  static const int minimumIterations = 50;
  static const double zoomLog2IterationStep = 32.0;

  const CpuIterationBudget._();

  static double normalizeZoom(double zoom) {
    if (!zoom.isFinite || zoom <= 0.0) return 1.0;
    return zoom;
  }

  static int forZoom({
    required int baseIterations,
    required int maxIterations,
    required double zoom,
  }) {
    final safeMaxIterations = math.max(minimumIterations, maxIterations);
    final normalizedZoom = normalizeZoom(zoom);
    final extraIterations = normalizedZoom <= 1.0
        ? 0
        : (math.log(normalizedZoom) / math.ln2 * zoomLog2IterationStep).round();

    return (baseIterations + extraIterations).clamp(
      minimumIterations,
      safeMaxIterations,
    );
  }
}

import 'package:flutter_fractals/features/renderer/cpu_iteration_budget.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('CpuIterationBudget', () {
    test('preserves zoom-depth iteration scaling contract', () {
      expect(
        CpuIterationBudget.forZoom(
          baseIterations: 120,
          maxIterations: 500,
          zoom: 1.0,
        ),
        120,
      );
      expect(
        CpuIterationBudget.forZoom(
          baseIterations: 120,
          maxIterations: 500,
          zoom: 4.0,
        ),
        184,
      );
      expect(
        CpuIterationBudget.forZoom(
          baseIterations: 490,
          maxIterations: 500,
          zoom: 4.0,
        ),
        500,
      );
    });

    test('normalizes malformed zoom samples before log/round', () {
      for (final zoom in [
        double.nan,
        double.infinity,
        double.negativeInfinity,
        0.0,
        -2.0,
      ]) {
        expect(
          CpuIterationBudget.normalizeZoom(zoom),
          1.0,
          reason: 'zoom=$zoom',
        );
        expect(
          CpuIterationBudget.forZoom(
            baseIterations: 120,
            maxIterations: 500,
            zoom: zoom,
          ),
          120,
          reason: 'zoom=$zoom',
        );
      }
    });

    test('keeps the minimum iteration floor replayable', () {
      expect(
        CpuIterationBudget.forZoom(
          baseIterations: 1,
          maxIterations: 10,
          zoom: 1.0,
        ),
        CpuIterationBudget.minimumIterations,
      );
    });
  });
}

